<?php require_once dirname(__DIR__) . '/includes/auth.php'; require_admin(); $pdo=db();
if(($_SERVER['REQUEST_METHOD']??'')==='POST'){$pdo->prepare('INSERT INTO email_templates (sequence_id,day_number,subject,html_body,plain_text_body,status) VALUES (?,?,?,?,?,?) ON DUPLICATE KEY UPDATE subject=VALUES(subject),html_body=VALUES(html_body),plain_text_body=VALUES(plain_text_body),status=VALUES(status)')->execute([$_POST['sequence_id'],$_POST['day_number'],$_POST['subject'],$_POST['html_body'],$_POST['plain_text_body'],$_POST['status']]);}
$seq=$pdo->query('SELECT * FROM email_sequences ORDER BY name')->fetchAll(); $rows=$pdo->query('SELECT t.*,s.name sequence_name FROM email_templates t JOIN email_sequences s ON s.id=t.sequence_id ORDER BY s.name,t.day_number')->fetchAll(); include '_header.php'; ?>
<h1>Email Templates</h1><div class="card"><p class="muted">Every email must include an unsubscribe link. If omitted, the mailer appends one automatically.</p><form method="post"><select name="sequence_id" required><?php foreach($seq as $s): ?><option value="<?=$s['id']?>"><?=e($s['name'])?></option><?php endforeach; ?></select><input type="number" min="1" name="day_number" placeholder="Day number" required><input name="subject" placeholder="Subject" required><textarea name="html_body" rows="8" placeholder="HTML body with {{first_name}}, {{unsubscribe_url}}" required></textarea><textarea name="plain_text_body" rows="5" placeholder="Plain text body"></textarea><select name="status"><option>active</option><option>paused</option></select><button>Save Template</button></form></div><table><tr><th>Sequence</th><th>Day</th><th>Subject</th><th>Status</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['sequence_name'])?></td><td><?=e($r['day_number'])?></td><td><?=e($r['subject'])?></td><td><?=e($r['status'])?></td></tr><?php endforeach; ?></table><?php include '_footer.php'; ?>
